import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  TextInput,
  StyleSheet,
  Alert,
  ActivityIndicator,
} from 'react-native';
import ReactNativeBiometrics from 'react-native-biometrics';
import AsyncStorage from '@react-native-async-storage/async-storage';
import CryptoJS from 'crypto-js';

const STORAGE_KEYS = {
  IS_AUTHENTICATED: '@auth_is_authenticated',
  PASSWORD_HASH: '@auth_password_hash',
  BIOMETRIC_ENABLED: '@auth_biometric_enabled',
  AUTH_TIMESTAMP: '@auth_timestamp',
};

const AUTH_EXPIRY_TIME = 24 * 60 * 60 * 1000;
const ENCRYPTION_KEY = 'your-secure-encryption-key-change-this';

const BiometricAuth = ({ onAuthSuccess }) => {
  const [loading, setLoading] = useState(true);
  const [biometricAvailable, setBiometricAvailable] = useState(false);
  const [biometricType, setBiometricType] = useState('');
  const [password, setPassword] = useState('');
  const [showPasswordInput, setShowPasswordInput] = useState(false);
  const [isSettingPassword, setIsSettingPassword] = useState(false);
  const [confirmPassword, setConfirmPassword] = useState('');

  const rnBiometrics = new ReactNativeBiometrics({
    allowDeviceCredentials: false,
  });

  useEffect(() => {
    initializeAuth();
  }, []);

  const initializeAuth = async () => {
    try {
      const isAuthenticated = await checkAuthenticationStatus();
      
      if (isAuthenticated) {
        onAuthSuccess();
        return;
      }

      const { available, biometryType } = await rnBiometrics.isSensorAvailable();
      setBiometricAvailable(available);
      setBiometricType(biometryType);

      const biometricEnabled = await AsyncStorage.getItem(STORAGE_KEYS.BIOMETRIC_ENABLED);
      const passwordHash = await AsyncStorage.getItem(STORAGE_KEYS.PASSWORD_HASH);

      if (!passwordHash) {
        setIsSettingPassword(true);
        setShowPasswordInput(true);
      } else if (available && biometricEnabled === 'true') {
        await promptBiometric();
      } else {
        setShowPasswordInput(true);
      }
    } catch (error) {
      console.error('Initialization error:', error);
      setShowPasswordInput(true);
    } finally {
      setLoading(false);
    }
  };

  const checkAuthenticationStatus = async () => {
    try {
      const authFlag = await AsyncStorage.getItem(STORAGE_KEYS.IS_AUTHENTICATED);
      const authTimestamp = await AsyncStorage.getItem(STORAGE_KEYS.AUTH_TIMESTAMP);

      if (authFlag === 'true' && authTimestamp) {
        const timestamp = parseInt(authTimestamp, 10);
        const currentTime = Date.now();

        if (currentTime - timestamp < AUTH_EXPIRY_TIME) {
          return true;
        } else {
          await clearAuthenticationStatus();
        }
      }
      return false;
    } catch (error) {
      console.error('Error checking auth status:', error);
      return false;
    }
  };

  const clearAuthenticationStatus = async () => {
    try {
      await AsyncStorage.multiRemove([
        STORAGE_KEYS.IS_AUTHENTICATED,
        STORAGE_KEYS.AUTH_TIMESTAMP,
      ]);
    } catch (error) {
      console.error('Error clearing auth status:', error);
    }
  };

  const setAuthenticationStatus = async () => {
    try {
      const timestamp = Date.now().toString();
      await AsyncStorage.multiSet([
        [STORAGE_KEYS.IS_AUTHENTICATED, 'true'],
        [STORAGE_KEYS.AUTH_TIMESTAMP, timestamp],
      ]);
    } catch (error) {
      console.error('Error setting auth status:', error);
      throw error;
    }
  };

  const hashPassword = (pwd) => {
    return CryptoJS.SHA256(pwd + ENCRYPTION_KEY).toString();
  };

  const promptBiometric = async () => {
    try {
      const { success } = await rnBiometrics.simplePrompt({
        promptMessage: 'Authenticate to continue',
        cancelButtonText: 'Use Password',
      });

      if (success) {
        await handleSuccessfulAuth();
      } else {
        setShowPasswordInput(true);
      }
    } catch (error) {
      console.error('Biometric authentication error:', error);
      Alert.alert(
        'Authentication Error',
        'Biometric authentication failed. Please use password.',
        [{ text: 'OK', onPress: () => setShowPasswordInput(true) }]
      );
    }
  };

  const handleSuccessfulAuth = async () => {
    try {
      await setAuthenticationStatus();
      onAuthSuccess();
    } catch (error) {
      console.error('Error handling successful auth:', error);
      Alert.alert('Error', 'Failed to save authentication status');
    }
  };

  const handlePasswordSubmit = async () => {
    if (!password.trim()) {
      Alert.alert('Error', 'Please enter a password');
      return;
    }

    if (isSettingPassword) {
      if (password.length < 8) {
        Alert.alert('Error', 'Password must be at least 8 characters long');
        return;
      }

      if (password !== confirmPassword) {
        Alert.alert('Error', 'Passwords do not match');
        return;
      }

      try {
        const hashedPassword = hashPassword(password);
        await AsyncStorage.setItem(STORAGE_KEYS.PASSWORD_HASH, hashedPassword);

        if (biometricAvailable) {
          Alert.alert(
            'Enable Biometric Authentication',
            `Would you like to enable ${biometricType} for faster login?`,
            [
              {
                text: 'No',
                onPress: async () => {
                  await AsyncStorage.setItem(STORAGE_KEYS.BIOMETRIC_ENABLED, 'false');
                  await handleSuccessfulAuth();
                },
              },
              {
                text: 'Yes',
                onPress: async () => {
                  await AsyncStorage.setItem(STORAGE_KEYS.BIOMETRIC_ENABLED, 'true');
                  await handleSuccessfulAuth();
                },
              },
            ]
          );
        } else {
          await handleSuccessfulAuth();
        }
      } catch (error) {
        console.error('Error setting password:', error);
        Alert.alert('Error', 'Failed to set password');
      }
    } else {
      try {
        const storedHash = await AsyncStorage.getItem(STORAGE_KEYS.PASSWORD_HASH);
        const inputHash = hashPassword(password);

        if (storedHash === inputHash) {
          await handleSuccessfulAuth();
        } else {
          Alert.alert('Error', 'Incorrect password');
          setPassword('');
        }
      } catch (error) {
        console.error('Error verifying password:', error);
        Alert.alert('Error', 'Failed to verify password');
      }
    }
  };

  const handleUseBiometric = () => {
    setShowPasswordInput(false);
    promptBiometric();
  };

  if (loading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#007AFF" />
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <View style={styles.content}>
        <Text style={styles.title}>
          {isSettingPassword ? 'Set Up Authentication' : 'Authentication Required'}
        </Text>

        {showPasswordInput ? (
          <View style={styles.passwordContainer}>
            <TextInput
              style={styles.input}
              placeholder={isSettingPassword ? 'Create Password' : 'Enter Password'}
              secureTextEntry
              value={password}
              onChangeText={setPassword}
              autoCapitalize="none"
              autoCorrect={false}
            />

            {isSettingPassword && (
              <TextInput
                style={styles.input}
                placeholder="Confirm Password"
                secureTextEntry
                value={confirmPassword}
                onChangeText={setConfirmPassword}
                autoCapitalize="none"
                autoCorrect={false}
              />
            )}

            <TouchableOpacity style={styles.button} onPress={handlePasswordSubmit}>
              <Text style={styles.buttonText}>
                {isSettingPassword ? 'Set Password' : 'Submit'}
              </Text>
            </TouchableOpacity>

            {!isSettingPassword && biometricAvailable && (
              <TouchableOpacity
                style={[styles.button, styles.secondaryButton]}
                onPress={handleUseBiometric}
              >
                <Text style={styles.secondaryButtonText}>
                  Use {biometricType}
                </Text>
              </TouchableOpacity>
            )}
          </View>
        ) : (
          <View style={styles.biometricContainer}>
            <Text style={styles.biometricText}>
              Authenticating with {biometricType}...
            </Text>
            <TouchableOpacity
              style={[styles.button, styles.secondaryButton]}
              onPress={() => setShowPasswordInput(true)}
            >
              <Text style={styles.secondaryButtonText}>Use Password Instead</Text>
            </TouchableOpacity>
          </View>
        )}
      </View>
    </View>
  );
};

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const handleAuthSuccess = () => {
    setIsAuthenticated(true);
  };

  const handleLogout = async () => {
    try {
      await AsyncStorage.multiRemove([
        STORAGE_KEYS.IS_AUTHENTICATED,
        STORAGE_KEYS.AUTH_TIMESTAMP,
      ]);
      setIsAuthenticated(false);
    } catch (error) {
      console.error('Logout error:', error);
    }
  };

  if (!isAuthenticated) {
    return <BiometricAuth onAuthSuccess={handleAuthSuccess} />;
  }

  return (
    <View style={styles.container}>
      <View style={styles.content}>
        <Text style={styles.title}>Welcome!</Text>
        <Text style={styles.subtitle}>You are authenticated</Text>
        <TouchableOpacity style={styles.button} onPress={handleLogout}>
          <Text style={styles.buttonText}>Logout</Text>
        </TouchableOpacity>
      </View>
    </View>
  );
};

